import React, { useState, useRef } from 'react'
import { Canvas, useLoader, useFrame } from '@react-three/fiber' // Added useFrame
import { Float, OrbitControls, Text } from '@react-three/drei'
import { TextureLoader } from 'three'
import confetti from 'canvas-confetti'

const EnvelopeCube = () => {
  const [isOpen, setIsOpen] = useState(false)
  const meshRef = useRef() // Create a reference to the mesh

  const textures = useLoader(TextureLoader, [
    '/assets/eid1.jpeg', '/assets/eid2.jpg', '/assets/eid3.jpg', 
    '/assets/eid4.jpg', '/assets/eid5.jpg', '/assets/eid6.jpg'
  ])

  // This runs every frame to rotate the cube
  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.5 // Constant rotation speed
    }
  })

  const handleClick = () => {
    setIsOpen(!isOpen)
    if (!isOpen) confetti({ particleCount: 100, spread: 70, origin: { y: 0.6 } })
  }

  return (
    <group ref={meshRef} onClick={handleClick} scale={0.6}>
      <mesh position={[isOpen ? -1.5 : 0, 0, 0]}>
        <boxGeometry args={[1.5, 1.5, 1.5]} />
        {textures.slice(0, 3).map((tex, i) => (
          <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>

      <mesh position={[isOpen ? 1.5 : 0, 0, 0]}>
        <boxGeometry args={[1.5, 1.5, 1.5]} />
        {textures.slice(3, 6).map((tex, i) => (
          <meshStandardMaterial key={i} attach={`material-${i}`} map={tex} />
        ))}
      </mesh>

      {isOpen && (
        <Float speed={2} floatIntensity={2}>
          <Text position={[0, 2, 0]} color="gold" fontSize={0.8}>
            Eid Mubarak!
          </Text>
        </Float>
      )}
    </group>
  )
}
export default function App() {
  return (
    <Canvas style={{ height: '100vh', background: '#0a192f' }}>
      <ambientLight intensity={0.8} />
      <EnvelopeCube />
      <OrbitControls />
    </Canvas>
  )
}
